const items = $input.all();
const today = new Date().toISOString().slice(0, 10);

const lines = items.map(function(item) {
  const m = item.json;
  const configured = Number(m.configured_fee).toFixed(2);
  const invoiced = Number(m.total_invoiced).toFixed(2);
  const delta = Number(m.fee_delta).toFixed(2);
  const sign = Number(m.fee_delta) > 0 ? '+' : '';
  return '- *' + m.account_name + '* | Sub: ' + m.subscription_name + ' | Plan: ' + m.plan_name + ' | Configured: $' + configured + ' | Invoiced: $' + invoiced + ' | Delta: ' + sign + '$' + delta;
}).join('\n');

const text = ':rotating_light: *Payment Gateway Fee Reconciliation Alert*\nDate: ' + today + ' | Window: Last 30 days\n\n*' + items.length + ' account(s) with fee mismatches found:*\n\n' + lines + '\n\n_Review in BigQuery: guesty-data.zuora_analytics_';

return [{ json: { slackText: text } }];
